import{_ as a,o as t,c as i,ag as h}from"./chunks/framework.CxZWPeXl.js";const d=JSON.parse('{"title":"Quản lý Giai đoạn","description":"","frontmatter":{},"headers":[],"relativePath":"admin-stages.md","filePath":"admin-stages.md"}'),o={name:"admin-stages.md"};function r(l,n,e,c,g,u){return t(),i("div",null,[...n[0]||(n[0]=[h('<h1 id="quan-ly-giai-đoan" tabindex="-1">Quản lý Giai đoạn <a class="header-anchor" href="#quan-ly-giai-đoan" aria-label="Permalink to &quot;Quản lý Giai đoạn&quot;">​</a></h1><blockquote><p>Xác định các giai đoạn thực hành bán hàng, thiết lập tiêu chuẩn và mục tiêu đánh giá.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Các giai đoạn bán hàng là nền tảng của bài thực hành. Mỗi giai đoạn đại diện cho một bước quyết định trong cuộc trò chuyện; AI sẽ theo dõi và đánh giá bạn dựa trên cấu hình này.</p><blockquote><p>Chỉ dành cho Quản trị viên có quyền Quản lý Giai đoạn.</p></blockquote><h2 id="cau-truc-trang" tabindex="-1">Cấu trúc Trang <a class="header-anchor" href="#cau-truc-trang" aria-label="Permalink to &quot;Cấu trúc Trang&quot;">​</a></h2><p>Các thẻ giai đoạn được sắp xếp theo số thứ tự:</p><ul><li><strong>Tiêu đề</strong>: Định dạng &quot;Giai đoạn N: {Tên Giai đoạn}&quot;</li><li><strong>Trạng thái Khách hàng</strong>: Trạng thái tâm lý hoặc hành vi hiện tại của khách hàng.</li><li><strong>Tùy chọn</strong>: Chỉnh sửa / Xóa.</li></ul><hr><h2 id="thuoc-tinh-giai-đoan" tabindex="-1">Thuộc tính Giai đoạn <a class="header-anchor" href="#thuoc-tinh-giai-đoan" aria-label="Permalink to &quot;Thuộc tính Giai đoạn&quot;">​</a></h2><h3 id="so-giai-đoan" tabindex="-1">Số Giai đoạn <a class="header-anchor" href="#so-giai-đoan" aria-label="Permalink to &quot;Số Giai đoạn&quot;">​</a></h3><ul><li>Xác định thứ tự. Phải là số nguyên dương và không được trùng lặp. Không thể sửa sau khi đã tạo.</li></ul><h3 id="ten-giai-đoan" tabindex="-1">Tên Giai đoạn <a class="header-anchor" href="#ten-giai-đoan" aria-label="Permalink to &quot;Tên Giai đoạn&quot;">​</a></h3><ul><li>Mục tiêu và tên gọi (VD: Phá băng, Khám phá nhu cầu).</li></ul><h3 id="trang-thai-khach-hang-hien-tai" tabindex="-1">Trạng thái Khách hàng Hiện tại <a class="header-anchor" href="#trang-thai-khach-hang-hien-tai" aria-label="Permalink to &quot;Trạng thái Khách hàng Hiện tại&quot;">​</a></h3><ul><li>Mô tả tâm lý khách hàng để AI dựa vào đó phản hồi (VD: &quot;Khách hàng còn e ngại và chưa tin tưởng&quot;).</li></ul><hr><h2 id="thao-tac" tabindex="-1">Thao tác <a class="header-anchor" href="#thao-tac" aria-label="Permalink to &quot;Thao tác&quot;">​</a></h2><ul><li><strong>Thêm Giai đoạn</strong>: Nhấp &quot;Thêm Giai đoạn&quot;. Điền Số, Tên, Mô tả.</li><li><strong>Chỉnh sửa</strong>: Nhấp &quot;Chỉnh sửa&quot; trên thẻ (Không sửa được Số Giai đoạn).</li><li><strong>Xóa</strong>: Nhấp &quot;Xóa&quot;. Có thể ảnh hưởng đến lịch sử trước đó.</li></ul><hr><h2 id="goi-y-thiet-ke" tabindex="-1">Gợi ý Thiết kế <a class="header-anchor" href="#goi-y-thiet-ke" aria-label="Permalink to &quot;Gợi ý Thiết kế&quot;">​</a></h2><ol><li><strong>Tiến trình hợp lý</strong>: Từ dễ đến khó, theo quy trình bán hàng tự nhiên.</li><li><strong>Mục tiêu rõ ràng</strong>: Mỗi giai đoạn nên có mục tiêu cụ thể, đo lường được.</li><li><strong>Mô tả chân thực</strong>: Trạng thái khách hàng phải phản ánh đúng tâm lý thực tế.</li><li><strong>Vừa phải</strong>: Từ 3-7 giai đoạn là hợp lý.</li></ol>',22)])])}const q=a(o,[["render",r]]);export{d as __pageData,q as default};
